Here's a simple state machine in C to manage user state transitions:
```c
#include <stdio.h>

// Enum for user states
typedef enum {
    LOGGED_OUT,
    LOGGED_IN
} user_state;

// Structure for the state machine
typedef struct {
    user_state current_state;
} state_machine;

// Initialize the state machine
void init_state_machine(state_machine *sm) {
    sm->current_state = LOGGED_OUT;
}

// Transition to the logged-in state
void login(state_machine *sm) {
    if (sm->current_state == LOGGED_OUT) {
        sm->current_state = LOGGED_IN;
        printf("Logged in successfully.\n");
    } else {
        printf("Already logged in.\n");
    }
}

// Transition to the logged-out state
void logout(state_machine *sm) {
    if (sm->current_state == LOGGED_IN) {
        sm->current_state = LOGGED_OUT;
        printf("Logged out successfully.\n");
    } else {
        printf("Already logged out.\n");
    }
}

// Check the current state
void print_state(state_machine *sm) {
    if (sm->current_state == LOGGED_IN) {
        printf("Current state: logged in.\n");
    } else {
        printf("Current state: logged out.\n");
    }
}

int main() {
    state_machine sm;
    init_state_machine(&sm);

    print_state(&sm);  // Initial state: logged out
    login(&sm);
    print_state(&sm);  // State after login: logged in
    logout(&sm);
    print_state(&sm);  // State after logout: logged out

    return 0;
}
```
