def assert_equal_with_message(actual, expected, message):
    """Assert that `actual` is equal to `expected` and raise an `AssertionError` with `message` if not."""
    assert actual == expected, message

def assert_decorator(func):
    """
    A decorator that wraps a function and calls `assert_equal_with_message` with the expected output as the third argument.
    """
    @wraps(func)
    def wrapper(*args, **kwargs):
        try:
            assert_equal_with_message(func(*args, **kwargs), func.__name__, f"Function {func.__name__} failed.")
            return func(*args, **kwargs)
        except AssertionError as e:
            raise ValueError(e)
    return wrapper
```

